#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int X, Y;
        scanf("%d %d", &X, &Y);
        int maxGoals = Y / 5; // integer division
        printf("%s\n", (maxGoals > X) ? "true" : "false");
    }
    return 0;
}

